var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"예─이! 다들 잘 지냈어?","JPN":"イェーイ！　みんな元気してる？","ENG":"EYYYY! How's everyone doing?","TWN":"哈～囉！大家好！"},"stage":{"bg":"HELI_NORMAL","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"언제나 여러분을 초 하이 텐션으로 가이드해 주는 건틀렛의 요정, 베티 미치야!","JPN":"毎回皆さんを超ハイテンションにガイドするガントレットの妖精、ベティー・ミッチーだよ！","ENG":"Batty Mitchie here, the Gauntlet fairy, and your guide to a hyper-active time!","TWN":"我是不管什麼時候都熱情替觀眾報導的聖鎧精靈，貝蒂·米琪！"},"stage":{"bg":"HELI_NORMAL","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"지금 우리가 있는 여기는 바로 샤레이드 상공! 엄청나! 화려해! 멋져!","JPN":"今私たちがいるここは、シャレードの上空！　すごい！　派手！　カッコいい！","ENG":"We are currently flying over the skies of Charade! Amazing! Cool! Rad!","TWN":"現在我們所在的位置是非常！華美！帥氣！的查雷德上空！"},"stage":{"bg":"HELI_NORMAL","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"하. 지. 만☆ 잠시 후면 이 도시는 불바다가 된다!","JPN":"で・も☆もうすぐこの街は火の海になるぞ！","ENG":"How. Ev. Er...☆ It won't be long until this city turns itself into the fiery pits of hell!","TWN":"但，是，呢☆只要再過一會兒這座城市就會陷入一片火海！"},"stage":{"bg":"HELI_NORMAL","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"샤레이드 건틀렛 리그! 태스크포스들끼리 치고 받는다는데 싫어할 사람 누구 있어~?","JPN":"シャレードガントレットリーグ！　タスクフォース同士で戦うっていうのに、イヤって人いる～？","ENG":"The Charade Gauntlet League! Who doesn't like the idea of TASKFORCEs fighting each other?","TWN":"查雷德聖鎧聯賽！說到特遣勢力之間的角力，有誰會不喜歡呢～？"},"stage":{"bg":"HELI_NORMAL","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"이번 시즌 슈퍼 루키는 누굴까? 화약 냄새 찡한 경기장을 불태울 염문설의 주인공은 과연?","JPN":"今シーズンのスーパールーキーは誰か？　火薬の匂いに溢れる競技場を燃やす、スキャンダルの主人公は？","ENG":"Who will be the super rookie of the season? Who's the mystery star that heated up the gunpowder-filled stadium with a hot scandal?","TWN":"誰將成為本賽季的超級新秀？在賽場上點燃戰火的主角究竟會是誰？"},"stage":{"bg":"HELI_NORMAL","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"뭣보다 엄마 젖이나 더 먹고 와야 할 최고의 꼴불견들도 빼놓을 수 없. 겠. 지?","JPN":"何より、まだまだママのおっぱいが必要なイカすベイビーたちのみっともない姿も、見・の・が・せ・ない！","ENG":"And of course, we can't forget about the worst losers who\xA0were born yesterday, can we?","TWN":"當然也不能錯過毛還沒長齊就來的最佳菜鳥選手，是，吧？"},"stage":{"bg":"HELI_NORMAL","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"이 밋치미치랑 함께 구경하면서 즐겁게 비웃어 주자구~","JPN":"このミッチーミッチーと一緒に見物しながら、楽しく笑ってやろう～","ENG":"Let's mock the heck out of them together, with Mitchie-Mitchie!","TWN":"還是回家找媽媽喝奶去吧！從現在開始，和米琪一起歡呼，一起盡情地嘲諷吧～"},"stage":{"bg":"HELI_NORMAL","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"안전 벨트 꽉 매시라! 놀라서 지려도 이 언니는 책임 안 질 테니까!","JPN":"シートベルトしっかり締めてね！　ビックリして漏らしても、お姉さんは知らないよ！","ENG":"Y'all folks better fasten your seat belts, because this is gonna be one hell of a ride.","TWN":"系好安全帶！萬一嚇到尿褲子米琪可不負責喔！"},"stage":{"bg":"HELI_NORMAL","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>알파트릭스 일렉트로닉스와 함께하는 이번 시즌! 베팅은 공식 홈페이지에서만 가능합니다!</color>","JPN":"<color=#ffd34c>アルファトリックス・エレクトロニクスが公式スポンサーとなっている今シーズン！　ベットは公式ホームページでのみ可能となっています！</color>","ENG":"<color=#ffd34c>This season is sponsored by Alphatrix Electronics! Bets are available through the official website only!</color>","TWN":"<color=#ffd34c>本賽季由阿爾法崔克斯電子贊助播出！前往官網為你喜歡的隊伍下注吧！</color>"},"stage":{"bg":"HELI_NORMAL","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……뭐라고 떠드는 건지 하나도 모르겠네.","JPN":"……何を言ってるのかさっぱりわからないや。","ENG":"...I didn't get a single word of what she said.","TWN":"……我完全聽不懂她在說什麼。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"걔 방송은 추천 안 해. 샤레이드에서 밋치보다 영양가 없는 리포터도 드물어.","JPN":"あの子の番組はおすすめしないよ。シャレードでミッチーほど足しにならないレポーターもそうそういないわ。","ENG":"Don't watch her show. It's hard to find someone more vulgar than Mitchie in Charade.","TWN":"我不推薦你聽她的節目。她是查雷德最沒營養的主播。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그러고 보니 미나는 건틀렛 리그에 나가 본 적 없다고 했지?","JPN":"そういえば、ミナはガントレットリーグに出たことないって言ってたよね？","ENG":"Come to think of it, you've never played in the Gauntlet League, Mina. Am I right?","TWN":"話說，米娜你說你從來沒參加過聖鎧聯賽是吧？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"아, 응. 모의전은 다른 소대랑 몇 번 하긴 했지만.","JPN":"あ、うん。模擬戦なら他の小隊と何度かやったことはあるけど。","ENG":"Oh, yeah. I tried a few mock battles with other squads.","TWN":"嗯，對，不過是和其他小隊進行過幾次模擬戰。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"규칙은 간단해. 공격 측은 수비측 거점을 점령하면 승리.","JPN":"ルールは簡単よ。攻撃側が守備側の拠点を占領すれば勝ちなの。","ENG":"The rules are simple. The offensive team wins by capturing the defensive team's base.","TWN":"規則很簡單。進攻的一方佔領防守方的據點就算獲勝。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"수비측은 제한 시간 동안 거점을 지키거나 공격측 거점을 점령하면 승리.","JPN":"守備側は制限時間内に拠点を守り切るか、攻撃側の拠点を占領すれば勝ち。","ENG":"The defensive team wins by either protecting their base during a set time, or capturing the offensive team's base.","TWN":"相反的，防守方在規定時間內守住據點，或者佔領進攻方的據點就算獲勝。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"팀은 정해진 포인트 내에서 장비를 준비해. 전차가 1,000 포인트면, 표준 단독 군장을 한 보병은 75 포인트인 식으로.","JPN":"チームは決められたポイント内で装備を準備するの。戦車が1,000ポイントだったら、標準単独軍装をした歩兵は75ポイント、みたいにね。","ENG":"Teams prepare their equipment within a fixed amount of points. For instance, a tank could be 1000 points, while a basic armored soldier could be worth 75 points.","TWN":"另外，隊伍需要在規定的點數內準備裝備。比如戰車是1,000點，標準裝備的一名步兵是75點。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"낭비 없이 장비를 편성하는 일도 스태프의 중요한 역할이야. 협찬사마다 분배도 다르거든.","JPN":"無駄のないように装備を編制することもスタッフの大事な役割なんだ。スポンサーによって分配も違うからね。","ENG":"It's important for the staff to purchase equipment efficiently and without waste. The distribution differs for sponsors.","TWN":"合理地採購裝備，減少浪費也是技術人員的重要任務。因為每個贊助商的分配也不一樣。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"기본은 페인트탄이고 필드에 따라 레이저 포인트도 사용 가능. 실탄 사용은 즉시 반칙패.","JPN":"基本はペイント弾で、フィールドによってレーザーポインターも使用可能。実弾の使用は即反則負け。","ENG":"Paintballs are the default option, but depending on the field, you can also use laser point guns. Live ammo is strictly prohibited and will lead to an immediate loss upon use.","TWN":"最基本的是漆彈，有些場地還可以使用雷射槍。但是使用實彈屬於犯規，會被取消比賽資格。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그 외에도 많긴 한데, 여긴 룰 위반도 들키지만 않으면 상관없다는 분위기라서. 하암….","JPN":"それ以外にもたくさんあるにはあるんだけど、ここはルール違反もバレなきゃ大丈夫って雰囲気だから。ふああ……","ENG":"There's more, but people won't care too much as long as you don't get caught. *Yawn*...","TWN":"除此之外還有很多規則，不過在這就算犯規，只要不被抓到就無所謂，哈啊……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"어째 졸려 보이네. 사장님도 아까부터 꾸벅꾸벅 졸고 있고.","JPN":"なんだか眠たそうだね。社長もさっきからうとうとしてるし。","ENG":"You look sleepy. Boss has also been dozing off every now and then.","TWN":"你好像很睏？老闆也是，從剛才開始就一直在打瞌睡。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"둘 다 요새 잠은 제대로 자는 거야?","JPN":"二人とも、最近ちゃんと寝てる？","ENG":"Are you two not getting enough sleep nowadays?","TWN":"你們二個最近都有好好睡覺嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"사장님에게 물어 봐. 며칠째 지하실에서 밤새도록 시달렸거든.","JPN":"社長に聞いてみたらいいわ。何日も地下室で徹夜でこき使われたんだから。","ENG":"Ask Boss. He spent the last few nights in the basement, working all night.","TWN":"你問老闆，這幾天我們一直在地下室熬夜。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"지하실……?","JPN":"地下室……？","ENG":"The basement...?","TWN":"地下室……？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"크흠, 흠. 미래를 위한 투자이니 이해해 주게나, 미나 양.","JPN":"こ、こほん。未来のための投資だから理解してくれたまえ、ミナ君。","ENG":"Ahem! Hmm, it's just an investment for the future, Mina.","TWN":"咳咳咳，這是為了未來的投資，米娜你先別管。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"읏~차. 그럼 슬슬 시작해 볼까?","JPN":"よいしょーっと。じゃあ、そろそろ始めようか？","ENG":"Phew! Well, then. Should we start now?","TWN":"嘿咻～那就開始囉？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"데이터 암호화 확인. 수신 감도 조정한 뒤에 각자 응답해.","JPN":"データ暗号化確認。受信感度を調整してから各自応答して。","ENG":"Data encryption confirmed. Adjust your reception sensitivity and reply.","TWN":"資料加密確認。各單位，調整好接收訊號後請回答。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"펠리세트. 수신 양호.","JPN":"フェリセット。受信良好。","ENG":"This is Félicette. Signals looking good.","TWN":"費莉塞特，訊號接收良好。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L41_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이쪽도야.","JPN":"こっちもだ。","ENG":"Same here.","TWN":"我這邊也良好。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L42_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"짘켭봦줏셍요! 미나 선배!","JPN":"みみゃもてくらさい！　ミナ先輩！","ENG":"Wrachtt mewoee, Mina!","TWN":"請…為…加油，米娜前輩！"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L45_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"노엘, 잡음이 너무 많아. 감도 15% 줄이고, 통신 딜레이 확인할게.","JPN":"ノエルは雑音が入りすぎ。感度を15％減らして通信のディレイを確認するね。","ENG":"Noelle, there's too much noise. Crank down the sensitivity to 15%. I'll check the delay.","TWN":"洛艾兒，你那邊雜訊太多。把感應調低15%，我確認一下通訊延遲。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앏베!","JPN":"あっ、あい！","ENG":"Ohrrrkaii!","TWN":"豪…的…！"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"방해 전파가 꽤 강하네. 로데오 워크스도 꽤 이를 갈고 나왔나 봐.","JPN":"妨害電波がかなり強いね。ロデオワークスも歯を食いしばって来たみたい。","ENG":"The disturbance signals are quite strong. Looks like Rodeo Works isn't here to fool around.","TWN":"干擾電波好強。看來羅德沃克斯也是有備而來。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"상대는 카운터 없이 5년 연속 본선 진출을 기록한 강호야. 다들 조심해.","JPN":"相手はカウンターがいないのに5年連続で本戦進出を果たした強豪だよ。みんな、気をつけて。","ENG":"Our opponents made it to the knockout stage five consecutive times without any Counters. Be careful.","TWN":"對手是在沒有制裁者的情況下，連續5年打入決賽的勁敵。大家都小心點。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……시작이네요. 마침내.","JPN":"……始まるわね。ついに。","ENG":"...So it begins. Finally.","TWN":"……終於要開始了。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"손은 왜 떠냐? 이제 와서 겁 먹었어?","JPN":"手が震えてるぞ。今更怖気付いたのか？","ENG":"Your hands are shaking. What are you, scared?","TWN":"你的手抖在什麼？現在才知道害怕嗎？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아뇨. 이건 흥분으로 떨고 있는 거예요.","JPN":"いいえ。これは武者震いよ。","ENG":"No. I'm shaking out of excitement.","TWN":"不，我是激動到發抖。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"작전은 사전에 공유한 대로예요. 전부 숙지했죠?","JPN":"作戦は事前に共有したとおり。全部熟知してるよね？","ENG":"We're going to stick with the plan I shared beforehand. You remember, right?","TWN":"就和我們事先商量好的那樣實施作戰，大家都清楚吧？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"일단은. 자잘한 부분은 임기응변으로 떼워야지, 뭐.","JPN":"一応は。細かい部分は臨機応変だな。","ENG":"For now. I guess we'll have to improvise the details.","TWN":"明白！其他瑣碎的細節就隨機應變吧？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"멋지게 이겨 봐요! 두 분의 데뷔전이니까요!","JPN":"カッコよく勝ちましょう！　お二人のデビュー戦ですから！","ENG":"Let's win this thing! It is your debut game, after all!","TWN":"讓我們打一場漂亮的勝仗吧！這可是大家的出道戰呢！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……사장님은 어떨 것 같아?","JPN":"……社長はどうなると思う？","ENG":"Well... What do you think, Boss?","TWN":"……老闆你覺得怎麼樣？"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"같이 훈련하는 내내 노엘이 매일 몸에 파스를 붙였거든.","JPN":"一緒に訓練してる間、ノエルは毎日身体にパスを貼ってた。","ENG":"Noelle has been putting cold and hot patches all over herself during training.","TWN":"訓練的這段時間，洛艾兒每天都貼著膏藥。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"펠리세트, 저 애는 밤 늦게까지 계속 우리 소대 작전 기록을 보면서 연구하고 있었고.","JPN":"フェリセットは夜遅くまでずっとうちの小隊の作戦記録を見ながら研究していたし。","ENG":"And that girl, Félicette, was up until late at night studying our past operation records.","TWN":"費莉塞特，那孩子夜裡一直研究我們小隊的作戰記錄到深夜。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"하지만 그렇게 해서… 정말 이길 수 있는 걸까?","JPN":"でも、そうやって……本当に勝てる？","ENG":"But... is that enough to win?","TWN":"但是這樣……真的就能贏嗎？"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"노력은 정직해도 성과는 그렇지 않아.","JPN":"努力は正直だが、成果はそうではない。","ENG":"No matter how hard you try, the results don't always align.","TWN":"努力未必就能換來好成績。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……알고 있어.","JPN":"……わかってる。","ENG":"...I know.","TWN":"……我知道。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그래도……. 아무 의미 없지 않았으면 좋겠는데.","JPN":"でも……何の意味もなく終わってほしくはないな。","ENG":"But still... I hope their effort doesn't go in vain.","TWN":"但我還是……希望她們所做的一切不是毫無意義的。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"다들 잘 보여? 발밑에서 펼쳐지고 있는 예선전 경기!","JPN":"みんな、ちゃんと見えてる？　眼下に広がる予選の様子！","ENG":"Can you see that, folks? The qualifiers have begun right beneath me!","TWN":"大家能看見嗎？在我們腳下展開的預賽！"},"stage":{"bg":"HELI_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"요즘 제일 핫하고 제일 부상자도 많은 단일전이라구!","JPN":"最近もっとも熱くて、もっとも怪我人の多い単一戦だよ！","ENG":"It's the most popular and most brutal mode, singles!","TWN":"這是最近最熱門，傷患最多的1v1戰！"},"stage":{"bg":"HELI_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"출전 태스크포스는 바로바로~ 로데오 워크스!","JPN":"出戦するタスクフォースは～ロデオワークス！","ENG":"Up here, we have the one and only Rodeo Works!","TWN":"參賽的特遣勢力就是～羅德沃克斯！"},"stage":{"bg":"HELI_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"카우보이들이니까 잔근육도 끝내 주려나? 살짝 심쿵해 버렸어☆","JPN":"カウボーイたちだから筋肉もすごいのかな？　ちょっとドキッとしちゃった☆","ENG":"Talk about cowboys! Ooh, I'm all in for those muscles! ☆","TWN":"哇喔！難道因為是牛仔，肌肉才這麼發達嗎？感覺有點心跳加速呢☆"},"stage":{"bg":"HELI_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"그리고 우리 카우보이 오빠들 상대는~ 코핀 컴퍼니의 카나리아 스쿼드!","JPN":"そして、カウボーイのお兄さんたちの相手は～コフィンカンパニーのカナリア・スクワッド！","ENG":"And our cowboys are up against Canary Squad from Coffin Company!","TWN":"牛仔們對上的是～科芬公司的金絲雀小隊！"},"stage":{"bg":"HELI_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"맞아! 관리국이 노리고 있다는 바로 그 태스크포스 13이 샤레이드에 전격 등장!","JPN":"そう！　管理局が狙っているという、あのタスクフォース13がシャレードに電撃登場！","ENG":"Yes, it's the problematic TASKFORCE 13 that's being chased by the Administration! Here, right in Charade!","TWN":"沒錯！就是被管理局盯上的那個第13特遣勢力，她們在查雷德閃亮登場！"},"stage":{"bg":"HELI_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"이면세계에서 엄~청 나댔다는데 과연? 샤레이드에서도 설칠 수 있을까?!","JPN":"裏世界でめっちゃめっちゃ出しゃばってたっていうけど、果たして？　シャレードでも出しゃばることができるかな？","ENG":"I hear that they've practically been flying around the battlefields of Counterside, buuut... how well will they do in Charade?!","TWN":"聽說她們在異界非～常囂張呢，她們在查雷德還能繼續囂張下去嗎？！"},"stage":{"bg":"HELI_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"미치밋치랑 같이 확인해 보자구~☆ Go~!","JPN":"ミッチーミッチーと一緒に確認してみよう～☆Go～！","ENG":"Let's find out with your one and only Mitchie-Mitchie! ☆ Let's go!","TWN":"和米琪一起拭目以待吧～☆ Let's GO～！"},"stage":{"bg":"HELI_NORMAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};